import{_ as t,o,c as a,a3 as d}from"./chunks/framework.BveOjhN0.js";const p=JSON.parse('{"title":"Tenant API v1 — Meetings","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Tenant API v1 — Meetings | SaleOS Docs"}],["meta",{"property":"og:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"property":"og:url","content":"https://docs.saleos.app/api/tenant-v1-meetings"}],["meta",{"property":"og:image","content":"https://docs.saleos.app/og-image.svg"}],["meta",{"name":"twitter:card","content":"summary_large_image"}],["meta",{"name":"twitter:title","content":"Tenant API v1 — Meetings | SaleOS Docs"}],["meta",{"name":"twitter:description","content":"Official documentation for the SaleOS SaaS Platform."}],["meta",{"name":"twitter:image","content":"https://docs.saleos.app/og-image.svg"}],["link",{"rel":"canonical","href":"https://docs.saleos.app/api/tenant-v1-meetings"}]]},"headers":[],"relativePath":"api/tenant-v1-meetings.md","filePath":"api/tenant-v1-meetings.md","lastUpdated":1784902400000}'),i={name:"api/tenant-v1-meetings.md"};function n(c,e,r,s,l,m){return o(),a("div",null,[...e[0]||(e[0]=[d('<h1 id="tenant-api-v1-—-meetings" tabindex="-1">Tenant API v1 — Meetings <a class="header-anchor" href="#tenant-api-v1-—-meetings" aria-label="Permalink to &quot;Tenant API v1 — Meetings&quot;">​</a></h1><p>Base path: <code>/api/tenant/v1</code></p><p>Middleware: <code>auth:tenant-api</code>, <code>tenant.user</code>, <code>verified</code>, <code>module:meetings</code>, plus <code>can:meetings.*</code> / policies.</p><p>Visibility: without <code>meetings.view_all</code>, only meetings where the actor is creator, host, or internal invitee.</p><h2 id="meetings" tabindex="-1">Meetings <a class="header-anchor" href="#meetings" aria-label="Permalink to &quot;Meetings&quot;">​</a></h2><h3 id="get-meetings" tabindex="-1">GET <code>/meetings</code> <a class="header-anchor" href="#get-meetings" aria-label="Permalink to &quot;GET `/meetings`&quot;">​</a></h3><p>Query: <code>search</code>, <code>status</code>, <code>from</code>, <code>to</code>, <code>host_id</code>, <code>visibility</code> (<code>created_by</code>|<code>host</code>|<code>attendee</code>), <code>page</code>, <code>per_page</code>.</p><h3 id="post-meetings" tabindex="-1">POST <code>/meetings</code> <a class="header-anchor" href="#post-meetings" aria-label="Permalink to &quot;POST `/meetings`&quot;">​</a></h3><p>Body:</p><table tabindex="0"><thead><tr><th>Field</th><th>Rules</th></tr></thead><tbody><tr><td><code>title</code></td><td>required, string</td></tr><tr><td><code>description</code></td><td>nullable</td></tr><tr><td><code>starts_at</code> / <code>ends_at</code></td><td>required; <code>ends_at</code> after <code>starts_at</code></td></tr><tr><td><code>timezone</code></td><td>required timezone</td></tr><tr><td><code>provider</code></td><td><code>none</code> | <code>google_meet</code> | <code>zoom</code> (default <code>none</code>)</td></tr><tr><td><code>join_url</code></td><td>nullable URL (manual link when <code>provider=none</code>)</td></tr><tr><td><code>host_id</code></td><td>optional; requires <code>meetings.assign_host</code> if not self</td></tr><tr><td><code>reminder_offset_minutes</code></td><td>nullable 0–10080</td></tr><tr><td><code>attendees[]</code></td><td>max 50; <code>{ user_id? }</code> and/or <code>{ email, name? }</code></td></tr></tbody></table><p>Creates Calendar projection (<code>source=meeting</code>). Provider ≠ <code>none</code> requires a connected workspace account.</p><h3 id="get-meetings-id" tabindex="-1">GET <code>/meetings/{id}</code> <a class="header-anchor" href="#get-meetings-id" aria-label="Permalink to &quot;GET `/meetings/{id}`&quot;">​</a></h3><h3 id="put-meetings-id" tabindex="-1">PUT <code>/meetings/{id}</code> <a class="header-anchor" href="#put-meetings-id" aria-label="Permalink to &quot;PUT `/meetings/{id}`&quot;">​</a></h3><p>Partial update of the same writable fields.</p><h3 id="post-meetings-id-cancel" tabindex="-1">POST <code>/meetings/{id}/cancel</code> <a class="header-anchor" href="#post-meetings-id-cancel" aria-label="Permalink to &quot;POST `/meetings/{id}/cancel`&quot;">​</a></h3><p>Sets <code>status=cancelled</code>, cancels reminder + Calendar projection, attempts remote provider cancel (best-effort).</p><h3 id="post-meetings-id-retry-sync" tabindex="-1">POST <code>/meetings/{id}/retry-sync</code> <a class="header-anchor" href="#post-meetings-id-retry-sync" aria-label="Permalink to &quot;POST `/meetings/{id}/retry-sync`&quot;">​</a></h3><p>Requires <code>meetings.update</code>. Retries provider create/update sync without unbounded re-queueing.</p><h3 id="delete-meetings-id" tabindex="-1">DELETE <code>/meetings/{id}</code> <a class="header-anchor" href="#delete-meetings-id" aria-label="Permalink to &quot;DELETE `/meetings/{id}`&quot;">​</a></h3><p>Soft delete; removes Calendar projection.</p><h3 id="post-meetings-id-assign-host" tabindex="-1">POST <code>/meetings/{id}/assign-host</code> <a class="header-anchor" href="#post-meetings-id-assign-host" aria-label="Permalink to &quot;POST `/meetings/{id}/assign-host`&quot;">​</a></h3><p>Body: <code>{ &quot;host_id&quot;: number }</code> — requires <code>meetings.assign_host</code>.</p><h2 id="integrations" tabindex="-1">Integrations <a class="header-anchor" href="#integrations" aria-label="Permalink to &quot;Integrations&quot;">​</a></h2><p>Requires <code>meetings.manage_integrations</code>.</p><table tabindex="0"><thead><tr><th>Method</th><th>Path</th><th>Purpose</th></tr></thead><tbody><tr><td>GET</td><td><code>/meetings/integrations</code></td><td>List providers, credential status, callback URL (no secrets)</td></tr><tr><td>PUT</td><td><code>/meetings/integrations/{provider}/credentials</code></td><td>Save workspace OAuth client ID/secret (+ optional webhook secret)</td></tr><tr><td>GET</td><td><code>/meetings/integrations/{provider}/authorize</code></td><td>Start OAuth using <strong>tenant</strong> credentials (one-time nonce in <code>state</code>)</td></tr><tr><td>DELETE</td><td><code>/meetings/integrations/{provider}</code></td><td>Disconnect account (keeps client credentials)</td></tr></tbody></table><p>Platform OAuth callback (no bearer token; tenant + one-time nonce from <code>state</code>):</p><p><code>GET /api/oauth/meetings/{provider}/callback</code></p><h2 id="webhooks" tabindex="-1">Webhooks <a class="header-anchor" href="#webhooks" aria-label="Permalink to &quot;Webhooks&quot;">​</a></h2><h3 id="post-meetings-webhooks-provider" tabindex="-1">POST <code>/meetings/webhooks/{provider}</code> <a class="header-anchor" href="#post-meetings-webhooks-provider" aria-label="Permalink to &quot;POST `/meetings/webhooks/{provider}`&quot;">​</a></h3><p>Unauthenticated, <code>throttle:webhooks</code>. <strong>Stub:</strong> custom <code>X-Meeting-Signature</code> HMAC ack only — not Zoom/Google-native event ingestion. Do not wire marketplace webhooks to this path in production yet.</p><h2 id="permissions" tabindex="-1">Permissions <a class="header-anchor" href="#permissions" aria-label="Permalink to &quot;Permissions&quot;">​</a></h2><p><code>meetings.view</code> · <code>create</code> · <code>update</code> · <code>delete</code> · <code>view_all</code> · <code>assign_host</code> · <code>manage_integrations</code></p><h2 id="notification-types" tabindex="-1">Notification types <a class="header-anchor" href="#notification-types" aria-label="Permalink to &quot;Notification types&quot;">​</a></h2><p><code>meeting.invite</code> · <code>meeting.updated</code> · <code>meeting.cancelled</code> · <code>meeting.reminder</code></p>',34)])])}const g=t(i,[["render",n]]);export{p as __pageData,g as default};
